211→export const CodeMirrorEditor = forwardRef<
212→  CodeMirrorEditorHandle,
213→  CodeMirrorEditorProps
214→>(function CodeMirrorEditor({ value, onChange, onValidationChange, isDarkMode = false }, ref) {
215→  const containerRef = useRef<HTMLDivElement>(null);
216→  const viewRef = useRef<EditorView | null>(null);
217→  const onChangeRef = useRef(onChange);
218→  const onValidationChangeRef = useRef(onValidationChange);
219→  const isExternalUpdate = useRef(false);
220→  const isDarkRef = useRef(isDarkMode);
221→
222→  onChangeRef.current = onChange;
223→  onValidationChangeRef.current = onValidationChange;
224→
225→  useImperativeHandle(ref, () => ({
226→    getValue: () => viewRef.current?.state.doc.toString() ?? '',
227→    setValue: (val: string) => {
228→      const view = viewRef.current;
229→      if (!view) return;
230→      isExternalUpdate.current = true;
231→      view.dispatch({
232→        changes: { from: 0, to: view.state.doc.length, insert: val },
233→      });
234→      isExternalUpdate.current = false;
235→    },
236→    getView: () => viewRef.current,
237→  }));
238→
239→  useEffect(() => {
240→    if (!containerRef.current) return;
241→
242→    const json5ParseLinter = linter(
243→      (view): Diagnostic[] => {
244→        const doc = view.state.doc.toString();
245→        if (!doc.trim()) return [];
246→        try {
247→          JSON5.parse(doc);
248→          onValidationChangeRef.current?.(false, null);
249→          return [];
250→        } catch (e) {
251→          const msg = (e as SyntaxError).message || 'Invalid JSON';
252→          const lineMatch = msg.match(/at (\d+):(\d+)/);
253→          let from = 0;
254→          let to = Math.min(doc.length, 1);
255→          if (lineMatch) {
256→            const line = parseInt(lineMatch[1], 10);
257→            const col = parseInt(lineMatch[2], 10);
258→            const lineInfo = view.state.doc.line(Math.min(line, view.state.doc.lines));
259→            from = lineInfo.from + Math.min(col - 1, lineInfo.length);
260→            to = Math.min(from + 1, lineInfo.to);
261→          }
262→          onValidationChangeRef.current?.(true, msg);
263→          return [{ from, to, severity: 'error', message: msg, source: 'json5' }];
264→        }
265→      },
266→      { delay: 300 },
267→    );
268→
269→    const schemaLinter = linter(sduiSchemaLinter, { delay: 500 });
270→
271→    const updateListener = EditorView.updateListener.of(update => {
272→      if (update.docChanged && !isExternalUpdate.current) {
273→        const doc = update.state.doc.toString();
274→        onChangeRef.current(doc);
275→      }
276→    });
277→
278→    const dark = isDarkRef.current;
279→    const themeExtension = dark ? darkTheme : lightTheme;
280→    const highlightExt = dark
281→      ? syntaxHighlighting(darkHighlightStyle)
282→      : syntaxHighlighting(defaultHighlightStyle, { fallback: true });
283→
284→    const state = EditorState.create({
285→      doc: value,
286→      extensions: [
287→        lineNumbers(),
288→        highlightActiveLineGutter(),
289→        highlightActiveLine(),
290→        drawSelection(),
291→        rectangularSelection(),
292→        bracketMatching(),
293→        foldGutter(),
294→        highlightSelectionMatches(),
295→        history(),
296→        javascript(),
297→        highlightExt,
298→        lintGutter(),
299→        json5ParseLinter,
300→        schemaLinter,
301→        themeExtension,
302→        updateListener,
303→        keymap.of([
304→          ...defaultKeymap,
305→          ...historyKeymap,
306→          ...foldKeymap,
307→          ...searchKeymap,
308→          indentWithTab,
309→        ]),
310→        EditorView.lineWrapping,
311→        EditorState.tabSize.of(2),
312→      ],
313→    });
314→
315→    const view = new EditorView({
316→      state,
317→      parent: containerRef.current,
318→    });
319→
320→    viewRef.current = view;
321→
322→    return () => {
323→      view.destroy();
324→      viewRef.current = null;
325→    };
326→  }, [isDarkMode]);
327→
328→  useEffect(() => {
329→    const view = viewRef.current;
330→    if (!view) return;
331→    const currentDoc = view.state.doc.toString();
332→    if (currentDoc !== value) {
333→      isExternalUpdate.current = true;
334→      view.dispatch({
335→        changes: { from: 0, to: view.state.doc.length, insert: value },
336→      });
337→      isExternalUpdate.current = false;
338→    }
339→  }, [value]);
340→
341→  return (
342→    <div
343→      ref={containerRef}
344→      style={{ height: '100%', overflow: 'hidden' }}
345→    />
346→  );
347→});
