 30→export function JsonEditorPanel() {
 31→  const state = useStorybookState();
 32→  const storyId = state.storyId ?? '';
 33→  const theme = useTheme();
 34→  const isDarkMode = theme.base === 'dark';
 35→
 36→  const [defaultJson, setDefaultJson] = useState<string>('');
 37→  const [text, setText] = useState<string>('');
 38→  const [error, setError] = useState<string | null>(null);
 39→  const [dirty, setDirty] = useState(false);
 40→  const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);
 41→  const editorRef = useRef<CodeMirrorEditorHandle>(null);
 42→  const retryRef = useRef<ReturnType<typeof setInterval> | null>(null);
 43→
 44→  const { stored, save, remove, ready } = useIndexedDB(idbKeyFor(storyId));
 45→
 46→  useEffect(() => {
 47→    return () => {
 48→      if (debounceRef.current) clearTimeout(debounceRef.current);
 49→      if (retryRef.current) clearInterval(retryRef.current);
 50→    };
 51→  }, []);
 52→
 53→  useEffect(() => {
 54→    const channel = getChannel();
 55→    if (!channel) return;
 56→
 57→    const onSetDefault = (json: string) => {
 58→      setDefaultJson(json);
 59→      if (retryRef.current) {
 60→        clearInterval(retryRef.current);
 61→        retryRef.current = null;
 62→      }
 63→    };
 64→
 65→    channel.on(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 66→    channel.emit(EVENTS.REQUEST_DEFAULT);
 67→
 68→    let retryCount = 0;
 69→    retryRef.current = setInterval(() => {
 70→      retryCount++;
 71→      if (retryCount > 20) {
 72→        if (retryRef.current) clearInterval(retryRef.current);
 73→        return;
 74→      }
 75→      channel.emit(EVENTS.REQUEST_DEFAULT);
 76→    }, 250);
 77→
 78→    return () => {
 79→      channel.off(EVENTS.SET_DEFAULT_JSON, onSetDefault);
 80→      if (retryRef.current) {
 81→        clearInterval(retryRef.current);
 82→        retryRef.current = null;
 83→      }
 84→    };
 85→  }, [storyId]);
 86→
 87→  useEffect(() => {
 88→    if (!ready || !defaultJson) return;
 89→    const initial = stored ?? defaultJson;
 90→    setText(initial);
 91→    editorRef.current?.setValue(initial);
 92→    setDirty(!!stored);
 93→    setError(null);
 94→  }, [ready, stored, defaultJson, storyId]);
 95→
 96→  const handleChange = useCallback(
 97→    (value: string) => {
 98→      setText(value);
 99→
100→      if (debounceRef.current) clearTimeout(debounceRef.current);
101→
102→      debounceRef.current = setTimeout(() => {
103→        const { parsed, error: parseErr } = tryParse(value);
104→        if (parsed !== null) {
105→          save(value);
106→          setDirty(true);
107→          getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
108→        } else {
109→          save(value);
110→          setDirty(true);
111→        }
112→      }, 400);
113→    },
114→    [save],
115→  );
116→
117→  const handleValidationChange = useCallback(
118→    (hasErrors: boolean, message: string | null) => {
119→      setError(hasErrors ? message : null);
120→    },
121→    [],
122→  );
123→
124→  const handleReset = useCallback(() => {
125→    remove();
126→    setText(defaultJson);
127→    editorRef.current?.setValue(defaultJson);
128→    setDirty(false);
129→    setError(null);
130→    const { parsed } = tryParse(defaultJson);
131→    if (parsed !== null) {
132→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
133→    }
134→  }, [defaultJson, remove]);
135→
136→  const handleFormat = useCallback(() => {
137→    const currentText = editorRef.current?.getValue() ?? '';
138→    const { parsed, error: parseErr } = tryParse(currentText);
139→    if (parsed !== null) {
140→      const formatted = JSON.stringify(parsed, null, 2);
141→      setText(formatted);
142→      editorRef.current?.setValue(formatted);
143→      save(formatted);
144→      getChannel()?.emit(EVENTS.UPDATE_JSON, parsed);
145→      setError(null);
146→    } else {
147→      setError(parseErr);
148→    }
149→  }, [save]);
150→
151→  const s = isDarkMode ? darkStyles : lightStyles;
152→
153→  if (!storyId) {
154→    return <div style={s.empty}>Select a story to edit its JSON.</div>;
155→  }
156→
157→  const isWaiting = !defaultJson && !text;
158→
159→  return (
160→    <div style={s.container}>
161→      <div style={s.toolbar}>
162→        <span style={s.label}>
163→          SDUI JSON {dirty && <span style={s.badge}>edited</span>}
164→        </span>
165→        <div style={s.actions}>
166→          <button style={s.btn} onClick={handleFormat}>
167→            Format
168→          </button>
169→          <button
170→            style={{ ...s.btn, ...s.btnReset }}
171→            onClick={handleReset}
172→            disabled={!dirty}
173→          >
174→            Reset
175→          </button>
176→        </div>
177→      </div>
178→
179→      {error && !isWaiting && <div style={s.error}>⚠ {error}</div>}
180→
181→      {isWaiting ? (
182→        <div style={s.empty}>
183→          Waiting for story to send SDUI JSON…
184→          <br />
185→          <span style={{ fontSize: 11, opacity: 0.7 }}>
186→            If this persists, the current story may not use useSDUIJsonEditor().
187→          </span>
188→        </div>
189→      ) : (
190→        <div style={s.editorContainer}>
191→          <CodeMirrorEditor
192→            ref={editorRef}
193→            value={text}
194→            onChange={handleChange}
195→            onValidationChange={handleValidationChange}
196→            isDarkMode={isDarkMode}
197→          />
198→        </div>
199→      )}
200→    </div>
201→  );
202→}
